import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as r,d}from"./app-802747a1.js";const o="/assets/net-img-890ac160-20230730162827-ogi0r5j-1b70d719.png",a="/assets/net-img-0a3e8319-20230730162827-qz6c4gr-504319e1.png",n={},s=d('<h1 id="发布订阅" tabindex="-1"><a class="header-anchor" href="#发布订阅" aria-hidden="true">#</a> 发布订阅</h1><p>进程间的一种消息通信模式：发送者（pub）发送消息，订阅者（sub）接收消息。Redis 客户端可以订阅任意数量的频道。</p><p>下图展示了频道 channel1 ， 以及订阅这个频道的三个客户端 —— client2 、 client5 和 client1 之间的关系：</p><figure><img src="'+o+'" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>当有新消息通过 PUBLISH 命令发送给频道 channel1 时， 这个消息就会被发送给订阅它的三个客户端：</p><figure><img src="'+a+'" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h2 id="命令" tabindex="-1"><a class="header-anchor" href="#命令" aria-hidden="true">#</a> 命令</h2><p>下表列出了 redis 发布订阅常用命令：</p><table><thead><tr><th style="text-align:left;">序号</th><th style="text-align:left;">命令及描述</th></tr></thead><tbody><tr><td style="text-align:left;">1</td><td style="text-align:left;"><code>PSUBSCRIBE pattern pattern ...</code> 订阅一个或多个符合给定模式的频道。</td></tr><tr><td style="text-align:left;">2</td><td style="text-align:left;"><code>PUBSUB subcommand [argument [argument ...]]</code> 查看订阅与发布系统状态。</td></tr><tr><td style="text-align:left;">3</td><td style="text-align:left;"><code>PUBLISH channel message</code> 将信息发送到指定的频道。</td></tr><tr><td style="text-align:left;">4</td><td style="text-align:left;"><code>PUNSUBSCRIBE [pattern [pattern ...]]</code> 退订所有给定模式的频道。</td></tr><tr><td style="text-align:left;">5</td><td style="text-align:left;"><code>SUBSCRIBE channel [channel ...]</code> 订阅给定的一个或多个频道的信息。</td></tr><tr><td style="text-align:left;">6</td><td style="text-align:left;"><code>UNSUBSCRIBE [channel [channel ...]]</code> 指退订给定的频道。</td></tr></tbody></table><h2 id="案例" tabindex="-1"><a class="header-anchor" href="#案例" aria-hidden="true">#</a> 案例</h2><p>先订阅后发布后才能收到消息，<br> 1、可以一次性订阅多个，<code>SUBSCRIBE c1 c2 c3</code></p><p>2、消息发布，<code>PUBLISH c1 helloworld</code></p><table><thead><tr><th>客户端1</th><th>客户端2</th></tr></thead><tbody><tr><td></td><td>127.0.0.1:6379&gt; SUBSCRIBE c1 c2 c3<br>Reading messages... (press Ctrl-C to quit)<br>1) &quot;subscribe&quot;<br>2) &quot;c1&quot;<br>3) (integer) 1<br>1) &quot;subscribe&quot;<br>2) &quot;c2&quot;<br>3) (integer) 2<br>1) &quot;subscribe&quot;<br>2) &quot;c3&quot;<br>3) (integer) 3</td></tr><tr><td>127.0.0.1:6379&gt; PUBLISH c1 helloworld<br>(integer) 1</td><td>1) &quot;message&quot;<br>2) &quot;c1&quot;<br>3) &quot;helloworld&quot;</td></tr></tbody></table><p>3、订阅多个，通配符<code>*</code>，<code>PSUBSCRIBE news*</code></p><p>4、收取消息，<code>PUBLISH new1 redis2015</code></p><table><thead><tr><th>客户端1</th><th>客户端2</th></tr></thead><tbody><tr><td></td><td>127.0.0.1:6379&gt; PSUBSCRIBE news*<br>Reading messages... (press Ctrl-C to quit)<br>1) &quot;psubscribe&quot;<br>2) &quot;news*&quot;<br>3) (integer) 1</td></tr><tr><td>127.0.0.1:6379&gt; PUBLISH news1 news2022<br>(integer) 1</td><td>1) &quot;pmessage&quot;<br>2) &quot;news*&quot;<br>3) &quot;news1&quot;<br>4) &quot;news2022&quot;</td></tr><tr><td>127.0.0.1:6379&gt; PUBLISH news121 news20221211<br>(integer) 1</td><td>1) &quot;pmessage&quot;<br>2) &quot;news*&quot;<br>3) &quot;news121&quot;<br>4) &quot;news20221211&quot;</td></tr></tbody></table>',16),l=[s];function i(c,u){return e(),r("div",null,l)}const h=t(n,[["render",i],["__file","发布订阅.html.vue"]]);export{h as default};
